export default function DeadlinesBoard() {
  const [clients, setClients] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    tools.host_listDeadlines({}).then((r) => {
      setClients(r.data || []);
      setLoading(false);
    });
  }, []);

  const now = new Date("2026-07-21");
  const endOfWeek = new Date(now);
  endOfWeek.setDate(now.getDate() + (7 - now.getDay()));
  const endOfMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0);

  const groups = [
    {
      key: "week",
      label: "This week",
      tone: "danger",
      clients: clients.filter((c) => {
        const d = new Date(c.filingDeadline);
        return d >= now && d <= endOfWeek;
      }),
    },
    {
      key: "month",
      label: "This month",
      tone: "warning",
      clients: clients.filter((c) => {
        const d = new Date(c.filingDeadline);
        return d > endOfWeek && d <= endOfMonth;
      }),
    },
    {
      key: "later",
      label: "Later",
      tone: "neutral",
      clients: clients.filter((c) => {
        const d = new Date(c.filingDeadline);
        return d > endOfMonth;
      }),
    },
  ];

  const daysUntil = (iso) => {
    const diff = new Date(iso) - now;
    return Math.ceil(diff / (1000 * 60 * 60 * 24));
  };

  const toneColors = {
    danger: { bg: "#fef2f2", border: "#fca5a5", badge: "#B0473A", badgeText: "#fff" },
    warning: { bg: "#fffbeb", border: "#fcd34d", badge: "#92400e", badgeText: "#fff" },
    neutral: { bg: "#f9f9f8", border: "#ECEBE8", badge: "#46443f", badgeText: "#fff" },
  };

  const statusVariant = (s) => {
    if (!s) return "neutral";
    if (s === "missing" || s === "overdue") return "danger";
    if (s === "needs_review" || s === "review") return "warning";
    if (s === "complete" || s === "verified") return "success";
    return "neutral";
  };

  const humanStatus = (s) => {
    if (!s) return "Unknown";
    return s.replace(/_/g, " ").replace(/\b\w/g, (c) => c.toUpperCase());
  };

  if (loading) {
    return (
      <div style={{ padding: 32, textAlign: "center", color: "var(--vendo-color-muted)", fontFamily: "var(--vendo-font-family)" }}>
        Loading deadlines…
      </div>
    );
  }

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 32, fontFamily: "var(--vendo-font-family)" }}>
      {groups.map((group) => {
        const colors = toneColors[group.tone];
        return (
          <div key={group.key}>
            <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 14 }}>
              <span style={{
                fontWeight: 600,
                fontSize: 15,
                color: "var(--vendo-color-text)",
              }}>{group.label}</span>
              <span style={{
                background: colors.badge,
                color: colors.badgeText,
                borderRadius: 99,
                fontSize: 12,
                fontWeight: 600,
                padding: "2px 10px",
              }}>{group.clients.length} client{group.clients.length !== 1 ? "s" : ""}</span>
            </div>

            {group.clients.length === 0 ? (
              <div style={{
                padding: "18px 20px",
                background: "var(--vendo-color-surface)",
                border: "1px solid var(--vendo-color-border)",
                borderRadius: "var(--vendo-radius-medium)",
                color: "var(--vendo-color-muted)",
                fontSize: 14,
              }}>
                {group.key === "week"
                  ? "No filing deadlines this week — nothing urgent."
                  : group.key === "month"
                  ? "No deadlines remaining this month."
                  : "No clients with later deadlines."}
              </div>
            ) : (
              <div style={{
                display: "grid",
                gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))",
                gap: 14,
              }}>
                {group.clients.map((client) => {
                  const days = daysUntil(client.filingDeadline);
                  const received = client.documentsReceived ?? 0;
                  const total = client.documentsTotal ?? 0;
                  const ratio = total > 0 ? received / total : 0;
                  const pct = Math.round(ratio * 100);
                  const missing = client.missingDocumentTypes || [];

                  return (
                    <div key={client.id} style={{
                      background: "var(--vendo-color-surface)",
                      border: `1px solid ${group.tone === "danger" && days <= 3 ? colors.border : "var(--vendo-color-border)"}`,
                      borderRadius: "var(--vendo-radius-medium)",
                      padding: "16px 18px",
                      display: "flex",
                      flexDirection: "column",
                      gap: 12,
                    }}>
                      {/* Header */}
                      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", gap: 8 }}>
                        <div>
                          <div style={{ fontWeight: 600, fontSize: 15, color: "var(--vendo-color-text)", lineHeight: 1.3 }}>
                            {client.name}
                          </div>
                          {client.entityType && (
                            <div style={{ fontSize: 12, color: "var(--vendo-color-muted)", marginTop: 2 }}>
                              {client.entityType.replace(/_/g, " ").replace(/\b\w/g, (c) => c.toUpperCase())}
                            </div>
                          )}
                        </div>
                        <div style={{
                          background: group.tone === "danger" ? colors.badge : group.tone === "warning" ? "#fef3c7" : "#f3f4f6",
                          color: group.tone === "danger" ? colors.badgeText : group.tone === "warning" ? "#92400e" : "#46443f",
                          borderRadius: 6,
                          fontSize: 12,
                          fontWeight: 600,
                          padding: "3px 8px",
                          whiteSpace: "nowrap",
                        }}>
                          {days === 0 ? "Due today" : days === 1 ? "1 day" : `${days} days`}
                        </div>
                      </div>

                      {/* Deadline */}
                      <div style={{ display: "flex", justifyContent: "space-between", fontSize: 13, color: "var(--vendo-color-muted)" }}>
                        <span>Filing deadline</span>
                        <span style={{ color: "var(--vendo-color-text)", fontWeight: 500 }}>
                          {new Date(client.filingDeadline).toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" })}
                        </span>
                      </div>

                      {/* Document progress */}
                      <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
                        <div style={{ display: "flex", justifyContent: "space-between", fontSize: 13 }}>
                          <span style={{ color: "var(--vendo-color-muted)" }}>Documents</span>
                          <span style={{ fontWeight: 600, color: pct === 100 ? "#166534" : group.tone === "danger" ? colors.badge : "var(--vendo-color-text)" }}>
                            {received} of {total} collected ({pct}%)
                          </span>
                        </div>
                        <div style={{
                          height: 6,
                          background: "#ECEBE8",
                          borderRadius: 99,
                          overflow: "hidden",
                        }}>
                          <div style={{
                            height: "100%",
                            width: `${pct}%`,
                            background: pct === 100 ? "#166534" : group.tone === "danger" ? colors.badge : "#111111",
                            borderRadius: 99,
                            transition: "width 0.4s ease",
                          }}/>
                        </div>
                      </div>

                      {/* Status */}
                      {client.status && (
                        <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                          <span style={{ fontSize: 12, color: "var(--vendo-color-muted)" }}>Status</span>
                          <span style={{
                            fontSize: 12,
                            fontWeight: 600,
                            padding: "2px 8px",
                            borderRadius: 99,
                            background:
                              client.status === "complete" ? "#dcfce7" :
                              client.status === "missing" || client.status === "overdue" ? "#fee2e2" :
                              client.status === "needs_review" ? "#fef3c7" : "#f3f4f6",
                            color:
                              client.status === "complete" ? "#166534" :
                              client.status === "missing" || client.status === "overdue" ? "#B0473A" :
                              client.status === "needs_review" ? "#92400e" : "#46443f",
                          }}>
                            {humanStatus(client.status)}
                          </span>
                        </div>
                      )}

                      {/* Missing doc types */}
                      {missing.length > 0 && (
                        <div style={{ borderTop: "1px solid var(--vendo-color-border)", paddingTop: 10 }}>
                          <div style={{ fontSize: 12, color: "var(--vendo-color-muted)", marginBottom: 5 }}>Still missing</div>
                          <div style={{ display: "flex", flexWrap: "wrap", gap: 5 }}>
                            {missing.slice(0, 4).map((doc, i) => (
                              <span key={i} style={{
                                fontSize: 11,
                                background: "#fef2f2",
                                color: "#B0473A",
                                border: "1px solid #fca5a5",
                                borderRadius: 4,
                                padding: "2px 7px",
                                fontWeight: 500,
                              }}>{doc}</span>
                            ))}
                            {missing.length > 4 && (
                              <span style={{ fontSize: 11, color: "var(--vendo-color-muted)", padding: "2px 4px" }}>
                                +{missing.length - 4} more
                              </span>
                            )}
                          </div>
                        </div>
                      )}

                      {/* Assigned staff */}
                      {client.assignedStaff && (
                        <div style={{ fontSize: 12, color: "var(--vendo-color-muted)" }}>
                          Assigned to <span style={{ color: "var(--vendo-color-text)", fontWeight: 500 }}>{client.assignedStaff}</span>
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}
